-- Delete Day 13 penalty payment events for all three
DELETE FROM payment_events WHERE id IN (450003, 450001, 450002);

-- Mark Day 13 logs as incomplete so they can still be counted (keep them as-is, just remove penalty)
-- No change needed to daily_logs - they're already marked incomplete

